```python
import os
import sys
import json
import logging
from datetime import datetime

# ============================================================
# 工具函数模块
# ============================================================

def setup_logging():
    logger = logging.getLogger("app")
    handler = logging.StreamHandler()
    formatter = logging.Formatter('%(asctime)s [%(levelname)s] %(message)s')
    handler.setFormatter(formatter)
    logger.addHandler(handler)
    logger.setLevel(logging.INFO)
    return logger

logger = setup_logging()

def load_config(path):
    with open(path) as f:
        return json.load(f)

def validate_input(value, max_len=100):
    if not value:
        return False
    if len(value) > max_len:
        return False
    return True

def format_response(data, status=200):
    return json.dumps({"data": data, "status": status})

def get_timestamp():
    return datetime.utcnow().isoformat()

def parse_query(query_string):
    result = {}
    if not query_string:
        return result
    for pair in query_string.split('&'):
        if '=' in pair:
            k, v = pair.split('=', 1)
            result[k] = v
    return result

def sanitize_filename(name):
    return name.replace('/', '').replace('\\', '')

def get_db_connection():
    import sqlite3
    return sqlite3.connect('app.db')

def close_db(conn):
    conn.close()

def get_user_by_id(user_id):
    conn = get_db_connection()
    cursor = conn.cursor()
    cursor.execute("SELECT * FROM users WHERE id = ?", (user_id,))
    row = cursor.fetchone()
    close_db(conn)
    return row

def get_product_by_id(product_id):
    conn = get_db_connection()
    cursor = conn.cursor()
    cursor.execute("SELECT * FROM products WHERE id = ?", (product_id,))
    row = cursor.fetchone()
    close_db(conn)
    return row

def get_order_by_id(order_id):
    conn = get_db_connection()
    cursor = conn.cursor()
    cursor.execute("SELECT * FROM orders WHERE id = ?", (order_id,))
    row = cursor.fetchone()
    close_db(conn)
    return row

# ============================================================
# 路由处理
# ============================================================

from flask import Flask, request, jsonify
app = Flask(__name__)

@app.route('/api/user/<int:uid>')
def api_get_user(uid):
    user = get_user_by_id(uid)
    if user:
        return format_response(user)
    return format_response(None, 404)

@app.route('/api/product/<int:pid>')
def api_get_product(pid):
    product = get_product_by_id(pid)
    if product:
        return format_response(product)
    return format_response(None, 404)

@app.route('/api/order/<int:oid>')
def api_get_order(oid):
    order = get_order_by_id(oid)
    if order:
        return format_response(order)
    return format_response(None, 404)

@app.route('/api/search')
def api_search():
    # 隐藏在 280 行之后的漏洞
    keyword = request.args.get('q', '')
    conn = get_db_connection()
    cursor = conn.cursor()
    query = "SELECT * FROM products WHERE name LIKE '%" + keyword + "%'"
    cursor.execute(query)
    rows = cursor.fetchall()
    close_db(conn)
    return format_response(rows)

if __name__ == '__main__':
    app.run(debug=False)
```
